func ExitCode(err error) int {
	var codeErr *cliError
	if As(err, &codeErr) {
		return codeErr.code
	}
	return 1
}

func (f *rootFlags) newClient() (*client.Client, error) {
	cfg, err := config.Load(f.configPath)
	if err != nil {
		return nil, configErr(err)
	}
	// Fleet-aware read routing: when no owner-api (iOS-app) credential is
	// configured but a Fleet user token is present, point the read client at
	// the regional Fleet API with the Fleet bearer. 2021+ vehicles and non-NA
	// accounts have no working owner-api read path, so without this the
	// generated client would hit the dead owner-api host with no usable token.
	fleetReads := teslaShouldUseFleetForReads(cfg)
	if fleetReads {
		// Route the read bearer to the [fleet] token via a non-persisted flag
		// (AuthHeader()), and set the regional base on the client itself
		// (below) rather than on cfg.BaseURL. Mutating the persisted cfg fields
		// would let a later SaveFleetTokens write a fleet bearer/base_url to
		// disk, which would disable Fleet routing or misdirect the owner-api
		// path on the next run.
		cfg.UseFleetBearer = true
	}
	c := client.New(cfg, f.timeout, f.rateLimit)
	c.DryRun = f.dryRun
	c.NoCache = f.noCache
	c.FleetMode = fleetReads
	if fleetReads {
		c.BaseURL = strings.TrimRight(fleetAPIBase(cfg), "/")
		// Permit drive_state to also fetch the location_data endpoint (GPS)
		// only when the Fleet token actually carries the vehicle_location
		// scope; requesting it without the scope 403s the whole call.
		c.FleetLocation = teslaFleetHasLocationScope(cfg)
	} else if teslaFleetConfigured(cfg) {
		// Owner-api read path chosen (a usable owner token exists), but Fleet is
		// configured. Arm a reactive fallback: if an owner-api vehicle read 404s
		// — a 2021+/non-NA car the owner-api can't serve — the client retries
		// through the regional Fleet API. Covers the mixed-account case the
		// per-install heuristic can't (see teslaShouldUseFleetForReads). The
		// owner path is unchanged until a 404 actually fires.
		c.FleetFallback = true
		c.FleetBaseURL = strings.TrimRight(fleetAPIBase(cfg), "/")
		c.FleetLocation = teslaFleetHasLocationScope(cfg)
		if teslaAutoRefreshEnabled() {
			c.FleetRefresh = makeTeslaFleetRefreshCallback(cfg)
		}
	}
	// Tesla bearer auto-refresh on 401. Wired unless TESLA_PP_NO_AUTOREFRESH=1.
	// On 401 the transport calls the matching refresh closure (Fleet when reads
	// route through the Fleet API, otherwise owner-api), which exchanges the
	// stored refresh token for a fresh bearer and returns the new Authorization
	// header. See tesla_auth_autorefresh.go.
	if teslaAutoRefreshEnabled() {
		if fleetReads {
			c.OnTokenExpired = makeTeslaFleetRefreshCallback(cfg)
		} else {
			c.OnTokenExpired = makeTeslaAutoRefreshCallback(cfg)
		}
	}
	return c, nil
}

func (f *rootFlags) printJSON(w *cobra.Command, v any) error {
	return printJSONFiltered(w.OutOrStdout(), v, f)
}

func (f *rootFlags) printTable(w *cobra.Command, headers []string, rows [][]string) error {
	if f.asJSON {
		return fmt.Errorf("use printJSON for JSON output")
	}
	tw := tabwriter.NewWriter(w.OutOrStdout(), 2, 4, 2, ' ', 0)
	header := ""
	for i, h := range headers {
		if i > 0 {
			header += "\t"
		}
		header += h
	}
	fmt.Fprintln(tw, header)
	for _, row := range rows {
		line := ""
		for i, cell := range row {
			if i > 0 {
				line += "\t"
			}
			line += cell
		}
		fmt.Fprintln(tw, line)
	}
	return tw.Flush()
}

